// Categorías y sus libros const CATEGORIES: Record<string, { name: string; testament: 'old' | 'new'; bookIds: string[] }> = { 'pentateuco': { name: 'Pentateuco', testament: 'old', bookIds: ['genesis', 'exodus', 'leviticus', 'numbers', 'deuteronomy'] }, 'historicos': { name: 'Libros Históricos', testament: 'old', bookIds: ['joshua', 'judges', 'ruth', '1samuel', '2samuel', '1kings', '2kings', '1chronicles', '2chronicles', 'ezra', 'nehemiah', 'tobit', 'judith', 'esther', '1maccabees', '2maccabees'] }, 'sapienciales': { name: 'Libros Sapienciales', testament: 'old', bookIds: ['job', 'psalms', 'proverbs', 'ecclesiastes', 'song', 'wisdom', 'sirach'] }, 'profetas mayores': { name: 'Profetas Mayores', testament: 'old', bookIds: ['isaiah', 'jeremiah', 'lamentations', 'baruch', 'ezekiel', 'daniel'] }, 'profetas menores': { name: 'Profetas Menores', testament: 'old', bookIds: ['hosea', 'joel', 'amos', 'obadiah', 'jonah', 'micah', 'nahum', 'habakkuk', 'zephaniah', 'haggai', 'zechariah', 'malachi'] }, 'evangelios': { name: 'Evangelios', testament: 'new', bookIds: ['matthew', 'mark', 'luke', 'john'] }, 'cartas de pablo': { name: 'Cartas de San Pablo', testament: 'new', bookIds: ['romans', '1corinthians', '2corinthians', 'galatians', 'ephesians', 'philippians', 'colossians', '1thessalonians', '2thessalonians', '1timothy', '2timothy', 'titus', 'philemon'] }, 'cartas catolicas': { name: 'Cartas Católicas', testament: 'new', bookIds: ['hebrews', 'james', '1peter', '2peter', '1john', '2john', '3john', 'jude'] }, };
// Función para normalizar texto (quitar acentos y minúsculas) const normalize = (text: string): string => { return text .toLowerCase() .normalize('NFD') .replace(/[\u0300-\u036f]/g, '') .trim(); };
// Expresión regular para detectar referencias bíblicas (ej: "Juan 3:16", "Genesis 1", "Salmo 23:1-5") const REFERENCE_REGEX = /^(.+?)\s*(\d+)(?::(\d+)(?:-(\d+))?)?$/i;
class SmartSearchService { /** * Búsqueda inteligente que detecta: * - Nombres de libros → navegar al libro * - Referencias (libro + capítulo) → navegar al capítulo * - Referencias con versículo → navegar al versículo * - Categorías → mostrar libros de esa categoría * - Texto libre → buscar en versículos */ async search(query: string): Promise<SmartSearchResult[]> { const results: SmartSearchResult[] = []; const normalizedQuery = normalize(query);
if (!normalizedQuery || normalizedQuery.length < 2) { return results; }
// 1. Detectar si es una referencia bíblica (ej: "Genesis 1:3" o "Juan 3") const referenceMatch = query.match(REFERENCE_REGEX); if (referenceMatch) { const [, bookPart, chapterStr, verseStart, verseEnd] = referenceMatch; const bookInfo = this.findBook(bookPart.trim());
if (bookInfo) { const chapter = parseInt(chapterStr);
if (verseStart) { // Es una referencia a versículo(s) results.push({ type: 'verse', title: `${bookInfo.name} ${chapter}:${verseStart}${verseEnd ? `-${verseEnd}` : ''}`, subtitle: t('search.goToVerse'), bookId: bookInfo.id, bookName: bookInfo.name, chapter, verse: parseInt(verseStart), testament: bookInfo.testament, }); } else { // Es una referencia a capítulo results.push({ type: 'chapter', title: `${bookInfo.name} ${chapter}`, subtitle: `${t('search.chapter')} ${chapter}`, bookId: bookInfo.id, bookName: bookInfo.name, chapter, testament: bookInfo.testament, }); } } }
// 2. Buscar libros que coincidan const matchingBooks = this.searchBooks(normalizedQuery); matchingBooks.forEach(book => { results.push({ type: 'book', title: book.name, subtitle: `${book.category} • ${book.testament === 'old' ? t('search.oldTestament') : t('search.newTestament')}`, bookId: book.id, bookName: book.name, testament: book.testament, category: book.category, }); });
// 3. Buscar categorías que coincidan const matchingCategories = this.searchCategories(normalizedQuery); matchingCategories.forEach(cat => { results.push({ type: 'category', title: cat.name, subtitle: `${cat.bookIds.length} ${t('search.books')} • ${cat.testament === 'old' ? t('search.oldTestament') : t('search.newTestament')}`, category: cat.name, testament: cat.testament, }); });
// 4. Si no encontramos nada estructurado, buscar en texto de versículos if (results.length === 0 || !referenceMatch) { try { const verseResults = await bibleService.searchVerses(query, { pageSize: 10 }); verseResults.results.forEach(result => { results.push({ type: 'verse', title: `${result.bookName} ${result.chapter}:${result.verse}`, subtitle: result.text.substring(0, 80) + (result.text.length > 80 ? '...' : ''), bookId: result.bookId, bookName: result.bookName, chapter: result.chapter, verse: result.verse, text: result.text, }); }); } catch (err) { console.error('[SmartSearch] Error buscando versículos:', err); } }
// Eliminar duplicados por bookId+chapter+verse const seen = new Set<string>(); return results.filter(r => { const key = `${r.type}-${r.bookId || ''}-${r.chapter || ''}-${r.verse || ''}-${r.category || ''}`; if (seen.has(key)) return false; seen.add(key); return true; }); }
/** * Buscar un libro por nombre o abreviación */ private findBook(name: string): { id: string; name: string; testament: 'old' | 'new'; category: string } | null { const normalized = normalize(name); return BOOK_NAMES[normalized] || null; }
/** * Buscar libros que coincidan parcialmente */ private searchBooks(query: string): { id: string; name: string; testament: 'old' | 'new'; category: string }[] { const results: { id: string; name: string; testament: 'old' | 'new'; category: string }[] = []; const seen = new Set<string>();
// Buscar coincidencias exactas primero const exactMatch = BOOK_NAMES[query]; if (exactMatch && !seen.has(exactMatch.id)) { results.push(exactMatch); seen.add(exactMatch.id); }
// Buscar coincidencias parciales Object.entries(BOOK_NAMES).forEach(([key, book]) => { if (!seen.has(book.id)) { if (key.includes(query) || normalize(book.name).includes(query)) { results.push(book); seen.add(book.id); } } });
return results.slice(0, 5); // Máximo 5 libros }
/** * Buscar categorías que coincidan */ private searchCategories(query: string): { name: string; testament: 'old' | 'new'; bookIds: string[] }[] { return Object.entries(CATEGORIES) .filter(([key, cat]) => key.includes(query) || normalize(cat.name).includes(query) ) .map(([, cat]) => cat) .slice(0, 3); // Máximo 3 categorías }
/** * Obtener sugerencias rápidas mientras se escribe */ getSuggestions(query: string): SmartSearchResult[] { const results: SmartSearchResult[] = []; const normalizedQuery = normalize(query);
if (!normalizedQuery || normalizedQuery.length < 1) { return results; }
// Buscar libros que empiecen con la query Object.entries(BOOK_NAMES).forEach(([key, book]) => { if (key.startsWith(normalizedQuery) || normalize(book.name).startsWith(normalizedQuery)) { if (!results.find(r => r.bookId === book.id)) { results.push({ type: 'book', title: book.name, subtitle: book.category, bookId: book.id, bookName: book.name, testament: book.testament, }); } } });
// Buscar categorías Object.entries(CATEGORIES).forEach(([key, cat]) => { if (key.startsWith(normalizedQuery) || normalize(cat.name).startsWith(normalizedQuery)) { results.push({ type: 'category', title: cat.name, subtitle: `${cat.bookIds.length} libros`, category: cat.name, testament: cat.testament, }); } });
return results.slice(0, 8); // Máximo 8 sugerencias } }
export const smartSearchService = new SmartSearchService();

